        fn: "Canvas 2D API",
        desc: "Draw shapes, paths, and text on a pixel-based canvas element.",
        category: "Rendering",
        subtitle: "Immediate mode — draw pixels, no retained scene graph",
        signature: "ctx.fillRect() | ctx.arc() | ctx.beginPath() | ctx.stroke()",
        descLong: "Canvas is an immediate-mode rendering API — you issue draw commands and pixels are written directly. No scene graph is retained; to redraw, you clear and redraw everything. Best for: high-frequency updates (games, animations), thousands of elements, pixel manipulation. Not ideal for: interactivity per element (no DOM nodes), accessibility, or sharp scaling.",
        examples: [
                  {
                            "tier": "intro",
                            "code": "// === ENTRY-LEVEL EXAMPLE ===\n// TASK      - Basic usage of Canvas 2D API — understand the core syntax and behavior.\n// APPROACH  - Simple example with minimal parameters; no edge cases.\n// STRENGTHS - Clear, readable; shows the fundamental pattern.\n// WEAKNESSES- Not production-ready; no error handling or complex scenarios.\n// APPROACH  - Basic shapes: rect, circle, text on canvas\n// STRENGTHS - Shows the core canvas drawing API\n// WEAKNESSES- No animation, no interactivity\n//\nconst canvas = document.getElementById('canvas');\nconst ctx = canvas.getContext('2d');\n// Rectangle\nctx.fillStyle = '#3498db';\nctx.fillRect(10, 10, 100, 50);\n// Circle (arc)\nctx.beginPath();\nctx.arc(200, 35, 25, 0, Math.PI * 2);\nctx.fillStyle = '#e74c3c';\nctx.fill();\n// Text\nctx.font = '16px sans-serif';\nctx.fillStyle = '#2c3e50';\nctx.fillText('Hello Canvas', 10, 100);\n// Line\nctx.beginPath();\nctx.moveTo(10, 120);\nctx.lineTo(200, 120);\nctx.strokeStyle = '#2ecc71';\nctx.lineWidth = 2;\nctx.stroke();"
                  },
                  {
                            "tier": "junior",
                            "code": "// === JUNIOR EXAMPLE ===\n// TASK      - Real-world usage of Canvas 2D API — common patterns you'll see in production.\n// APPROACH  - Combine Canvas 2D API with related functions; handle common edge cases.\n// STRENGTHS - Practical; covers the 80% use cases encountered on the job.\n// WEAKNESSES- May need optimization for large datasets or complex queries.\n// APPROACH  - Animation loop, gradients, paths, image data\n// STRENGTHS - Covers the 80% of canvas usage\n// WEAKNESSES- No HiDPI, no hit detection\n//\n// 1) ANIMATION LOOP — requestAnimationFrame\nfunction animate() {\n  ctx.clearRect(0, 0, canvas.width, canvas.height);\n  // Draw frame\n  ctx.fillStyle = '#3498db';\n  ctx.fillRect(x, y, 50, 50);\n  x += 2;  // move right\n  requestAnimationFrame(animate);\n}\n// animate();\n// 2) GRADIENT — linear and radial\nconst linear = ctx.createLinearGradient(0, 0, 200, 0);\nlinear.addColorStop(0, '#3498db');\nlinear.addColorStop(1, '#e74c3c');\nctx.fillStyle = linear;\nctx.fillRect(10, 10, 200, 50);\nconst radial = ctx.createRadialGradient(100, 100, 10, 100, 100, 80);\nradial.addColorStop(0, '#fff');\nradial.addColorStop(1, '#000');\nctx.fillStyle = radial;\nctx.beginPath();\nctx.arc(100, 100, 80, 0, Math.PI * 2);\nctx.fill();\n// 3) COMPLEX PATH — bezier curves\nctx.beginPath();\nctx.moveTo(50, 200);\nctx.quadraticCurveTo(100, 100, 200, 200);  // control point, end\nctx.bezierCurveTo(250, 150, 300, 250, 350, 200);  // cp1, cp2, end\nctx.strokeStyle = '#9b59b6';\nctx.lineWidth = 3;\nctx.stroke();\n// 4) IMAGE DATA — pixel-level manipulation\nconst imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);\nfor (let i = 0; i < imageData.data.length; i += 4) {\n  imageData.data[i]     = 255 - imageData.data[i];     // R invert\n  imageData.data[i + 1] = 255 - imageData.data[i + 1]; // G invert\n  imageData.data[i + 2] = 255 - imageData.data[i + 2]; // B invert\n}\nctx.putImageData(imageData, 0, 0);"
                  },
                  {
                            "tier": "senior",
                            "code": "// === SENIOR EXAMPLE ===\n// TASK      - Advanced usage of Canvas 2D API — performance, edge cases, and expert patterns.\n// APPROACH  - Production-grade patterns; optimization; handling complex scenarios.\n// STRENGTHS - Complete; handles edge cases, performance, and maintainability.\n// WEAKNESSES- Complex; requires deep knowledge to understand and maintain.\n// APPROACH  - HiDPI scaling, hit detection, offscreen canvas, decision guide\n// STRENGTHS - Production canvas patterns\n// WEAKNESSES- N/A\n//\n// 1) HIDPI / RETINA — scale canvas for sharp rendering\nfunction setupHiDPI(canvas) {\n  const dpr = window.devicePixelRatio || 1;\n  const rect = canvas.getBoundingClientRect();\n  canvas.width = rect.width * dpr;\n  canvas.height = rect.height * dpr;\n  const ctx = canvas.getContext('2d');\n  ctx.scale(dpr, dpr);\n  canvas.style.width = rect.width + 'px';\n  canvas.style.height = rect.height + 'px';\n  return ctx;\n}\n// 2) HIT DETECTION — map mouse click to drawn element\nclass CanvasScene {\n  #shapes = [];\n  add(shape) { this.#shapes.push(shape); }\n  draw(ctx) {\n    ctx.clearRect(0, 0, ctx.canvas.width, ctx.canvas.height);\n    this.#shapes.forEach(s => s.draw(ctx));\n  }\n  hitTest(x, y) {\n    // Iterate in reverse (topmost first)\n    for (let i = this.#shapes.length - 1; i >= 0; i--) {\n      if (this.#shapes[i].contains(x, y)) return this.#shapes[i];\n    }\n    return null;\n  }\n}\nclass CircleShape {\n  constructor(x, y, r, color) { this.x = x; this.y = y; this.r = r; this.color = color; }\n  draw(ctx) {\n    ctx.beginPath(); ctx.arc(this.x, this.y, this.r, 0, Math.PI * 2);\n    ctx.fillStyle = this.color; ctx.fill();\n  }\n  contains(x, y) {\n    return Math.hypot(x - this.x, y - this.y) <= this.r;\n  }\n}\n// 3) OFFSCREEN CANVAS — render in a worker (browser support: Chrome, Edge)\n// const offscreen = new OffscreenCanvas(800, 600);\n// const offCtx = offscreen.getContext('2d');\n// Transfer to worker: worker.postMessage({ canvas: offscreen }, [offscreen]);\n// 4) PERFORMANCE — batch draw calls, minimize state changes\nfunction drawManyRects(ctx, rects) {\n  // Group by color to minimize fillStyle changes\n  const byColor = new Map();\n  for (const r of rects) {\n    (byColor.get(r.color) ?? byColor.set(r.color, []).get(r.color)).push(r);\n  }\n  for (const [color, group] of byColor) {\n    ctx.fillStyle = color;\n    for (const r of group) ctx.fillRect(r.x, r.y, r.w, r.h);\n  }\n}\n// Decision rule:\n//   high-frequency animation (60fps)                       -> canvas\n//   thousands of elements                                  -> canvas\n//   pixel manipulation                                     -> canvas + ImageData\n//   need per-element interactivity                         -> SVG or canvas hit detection\n//   need accessibility                                     -> SVG (DOM elements have ARIA)\n//   need sharp scaling                                     -> SVG (vector) or HiDPI canvas\n//   need to render in a worker                             -> OffscreenCanvas\n//   charts with < 1000 elements                            -> SVG (D3, etc.)\n//\n// Anti-pattern: using canvas for a static chart with 10 bars;\n//   SVG is simpler, accessible, and has built-in interactivity via DOM events."
                  }
        ],
