                            "code": "// === ENTRY-LEVEL EXAMPLE ===\n// TASK      - Basic usage of SVG & D3 Fundamentals — understand the core syntax and behavior.\n// APPROACH  - Simple example with minimal parameters; no edge cases.\n// STRENGTHS - Clear, readable; shows the fundamental pattern.\n// WEAKNESSES- Not production-ready; no error handling or complex scenarios.\n// APPROACH  - SVG elements via DOM API and D3 data join\n// STRENGTHS - Shows both raw SVG and D3 patterns\n// WEAKNESSES- No scales, no axes\n//\n// 1) RAW SVG — create elements with DOM API\nconst svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');\nsvg.setAttribute('width', 200);\nsvg.setAttribute('height', 100);\nconst rect = document.createElementNS('http://www.w3.org/2000/svg', 'rect');\nrect.setAttribute('x', 10); rect.setAttribute('y', 10);\nrect.setAttribute('width', 80); rect.setAttribute('height', 50);\nrect.setAttribute('fill', '#3498db');\nsvg.appendChild(rect);\ndocument.body.appendChild(svg);\n// 2) D3 DATA JOIN — bind data to elements\n// import * as d3 from 'd3';\n// const data = [10, 20, 30, 40];\n// d3.select('svg')\n//   .selectAll('rect')\n//   .data(data)\n//   .join('rect')\n//   .attr('x', (d, i) => i * 25)\n//   .attr('y', (d) => 100 - d)\n//   .attr('width', 20)\n//   .attr('height', (d) => d)\n//   .attr('fill', '#3498db');"
